type Item = { type: string };
type Step = { items: Item[] };
type Scenario = { steps: Step[] };

const basePremiumFor = (item: Item): number =>
  BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;

const quotePremiumFor = (step: Step): number => {
  const itemsBaseTotal = step.items.reduce(
    (sum, item) => sum + basePremiumFor(item),
    0,
  );
  return itemsBaseTotal + PROCESSING_FEE;
};

export const processScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: [{ premium: quotePremiumFor(scenario.steps[0]) }] };
};
